 95→/**
 96→ * Analyze a session and generate insights, saving them to SQLite.
 97→ */
 98→export async function analyzeSession(
 99→  session: SessionData,
100→  messages: SQLiteMessageRow[],
101→  options?: AnalysisOptions
102→): Promise<AnalysisResult> {
103→  if (!isLLMConfigured()) {
104→    return {
105→      success: false,
106→      insights: [],
107→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
108→    };
109→  }
110→
111→  if (messages.length === 0) {
112→    return {
113→      success: false,
114→      insights: [],
115→      error: 'No messages found for this session.',
116→    };
117→  }
118→
119→  try {
120→    const client = createLLMClient();
121→    const formattedMessages = formatMessagesForAnalysis(messages);
122→    const estimatedTokens = client.estimateTokens(formattedMessages);
123→
124→    let analysisResponse: AnalysisResponse;
125→    let totalInputTokens = 0;
126→    let totalOutputTokens = 0;
127→
128→    if (estimatedTokens > MAX_INPUT_TOKENS) {
129→      // Chunk the messages and analyze separately
130→      const chunks = chunkMessages(messages, client.estimateTokens.bind(client));
131→      const chunkResponses: AnalysisResponse[] = [];
132→      const totalChunks = chunks.length;
133→
134→      for (let i = 0; i < chunks.length; i++) {
135→        const chunk = chunks[i];
136→        options?.onProgress?.({ phase: 'analyzing', currentChunk: i + 1, totalChunks });
137→
138→        const chunkFormatted = formatMessagesForAnalysis(chunk);
139→        const prompt = generateSessionAnalysisPrompt(
140→          session.project_name,
141→          session.summary,
142→          chunkFormatted
143→        );
144→
145→        const response = await client.chat([
146→          { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
147→          { role: 'user', content: prompt },
148→        ], { signal: options?.signal });
149→
150→        if (response.usage) {
151→          totalInputTokens += response.usage.inputTokens;
152→          totalOutputTokens += response.usage.outputTokens;
153→        }
154→
155→        const parsed = parseAnalysisResponse(response.content);
156→        if (parsed.success) chunkResponses.push(parsed.data);
157→      }
158→
159→      if (chunkResponses.length === 0) {
160→        return {
161→          success: false,
162→          insights: [],
163→          error: 'All chunks failed to parse LLM response',
164→          error_type: 'json_parse_error',
165→          usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
166→        };
167→      }
168→
169→      analysisResponse = mergeAnalysisResponses(chunkResponses);
170→
171→      // Chunked sessions: extract facets separately using lightweight prompt
172→      // (facets are holistic — can't be merged across chunks)
173→      if (!analysisResponse.facets) {
174→        try {
175→          const firstMsgs = formatMessagesForAnalysis(messages.slice(0, 20));
176→          const lastMsgs = formatMessagesForAnalysis(messages.slice(-20));
177→          const facetPrompt = generateFacetOnlyPrompt(
178→            session.project_name,
179→            session.summary,
180→            firstMsgs,
181→            lastMsgs
182→          );
183→
184→          const facetResponse = await client.chat([
185→            { role: 'system', content: FACET_ONLY_SYSTEM_PROMPT },
186→            { role: 'user', content: facetPrompt },
187→          ], { signal: options?.signal });
188→
189→          if (facetResponse.usage) {
190→            totalInputTokens += facetResponse.usage.inputTokens;
191→            totalOutputTokens += facetResponse.usage.outputTokens;
192→          }
193→
194→          const facetJson = extractJsonPayload(facetResponse.content);
195→          if (facetJson) {
196→            try {
197→              analysisResponse.facets = JSON.parse(facetJson);
198→            } catch {
199→              // jsonrepair fallback
200→              try {
201→                analysisResponse.facets = JSON.parse(jsonrepair(facetJson));
202→              } catch {
203→                // Facet extraction failed for chunked session — non-fatal
204→              }
205→            }
206→          }
207→        } catch {
208→          // Facet extraction failed for chunked session — non-fatal, continue
209→        }
210→      }
211→    } else {
212→      options?.onProgress?.({ phase: 'analyzing', currentChunk: 1, totalChunks: 1 });
213→      const prompt = generateSessionAnalysisPrompt(
214→        session.project_name,
215→        session.summary,
216→        formattedMessages
217→      );
218→
219→      const response = await client.chat([
220→        { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
221→        { role: 'user', content: prompt },
222→      ], { signal: options?.signal });
223→
224→      if (response.usage) {
225→        totalInputTokens = response.usage.inputTokens;
226→        totalOutputTokens = response.usage.outputTokens;
227→      }
228→
229→      const parsed = parseAnalysisResponse(response.content);
230→      if (!parsed.success) {
231→        return {
232→          success: false,
233→          insights: [],
234→          error: 'Failed to parse LLM response. Please try again.',
235→          error_type: parsed.error.error_type,
236→          response_length: parsed.error.response_length,
237→          response_preview: parsed.error.response_preview,
238→        };
239→      }
240→
241→      analysisResponse = parsed.data;
242→    }
243→
244→    options?.onProgress?.({ phase: 'saving' });
245→    const insights = convertToInsightRows(analysisResponse, session);
246→
247→    // Save new insights first, then delete old non-prompt-quality insights
248→    // (safe order: if save fails, old data is preserved)
249→    saveInsightsToDb(insights);
250→    deleteSessionInsights(session.id, {
251→      excludeTypes: ['prompt_quality'],
252→      excludeIds: insights.map(i => i.id),
253→    });
254→
255→    // Save facets if extracted
256→    if (analysisResponse.facets) {
257→      saveFacetsToDb(session.id, analysisResponse.facets, ANALYSIS_VERSION);
258→    }
259→
260→    // Update session character if LLM classified it
261→    if (analysisResponse.session_character) {
262→      const db = getDb();
263→      db.prepare('UPDATE sessions SET session_character = ? WHERE id = ?')
264→        .run(analysisResponse.session_character, session.id);
265→    }
266→
267→    return {
268→      success: true,
269→      insights,
270→      usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
271→    };
272→  } catch (error) {
273→    if (error instanceof Error && error.name === 'AbortError') {
274→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
275→    }
276→    return {
277→      success: false,
278→      insights: [],
279→      error: error instanceof Error ? error.message : 'Analysis failed',
280→      error_type: 'api_error',
281→    };
282→  }
283→}
