285→/**
286→ * Analyze prompt quality for a session.
287→ */
288→export async function analyzePromptQuality(
289→  session: SessionData,
290→  messages: SQLiteMessageRow[],
291→  options?: AnalysisOptions
292→): Promise<AnalysisResult> {
293→  if (!isLLMConfigured()) {
294→    return {
295→      success: false,
296→      insights: [],
297→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
298→    };
299→  }
300→
301→  if (messages.length === 0) {
302→    return {
303→      success: false,
304→      insights: [],
305→      error: 'No messages found for this session.',
306→    };
307→  }
308→
309→  const userMessages = messages.filter(m => m.type === 'user');
310→  if (userMessages.length < 2) {
311→    return {
312→      success: false,
313→      insights: [],
314→      error: 'Not enough user messages to analyze prompt quality (need at least 2).',
315→    };
316→  }
317→
318→  try {
319→    const client = createLLMClient();
320→    const formattedMessages = formatMessagesForAnalysis(messages);
321→
322→    let analysisInput = formattedMessages;
323→    const estimatedTokens = client.estimateTokens(formattedMessages);
324→    if (estimatedTokens > MAX_INPUT_TOKENS) {
325→      const targetLength = Math.floor((MAX_INPUT_TOKENS / estimatedTokens) * formattedMessages.length * 0.8);
326→      analysisInput = formattedMessages.slice(0, targetLength) + '\n\n[... conversation truncated for analysis ...]';
327→    }
328→
329→    const prompt = generatePromptQualityPrompt(
330→      session.project_name,
331→      analysisInput,
332→      messages.length
333→    );
334→
335→    options?.onProgress?.({ phase: 'analyzing' });
336→    const response = await client.chat([
337→      { role: 'system', content: PROMPT_QUALITY_SYSTEM_PROMPT },
338→      { role: 'user', content: prompt },
339→    ], { signal: options?.signal });
340→
341→    const parsed = parsePromptQualityResponse(response.content);
342→    if (!parsed.success) {
343→      return {
344→        success: false,
345→        insights: [],
346→        error: 'Failed to parse prompt quality analysis. Please try again.',
347→        error_type: parsed.error.error_type,
348→        response_length: parsed.error.response_length,
349→        response_preview: parsed.error.response_preview,
350→      };
351→    }
352→
353→    options?.onProgress?.({ phase: 'saving' });
354→    const insight = convertPromptQualityToInsightRow(parsed.data, session);
355→
356→    // Save new insight, then delete old prompt_quality insights
357→    saveInsightsToDb([insight]);
358→    deleteSessionInsights(session.id, {
359→      includeOnlyTypes: ['prompt_quality'],
360→      excludeIds: [insight.id],
361→    });
362→
363→    return {
364→      success: true,
365→      insights: [insight],
366→      usage: response.usage ? {
367→        inputTokens: response.usage.inputTokens,
368→        outputTokens: response.usage.outputTokens,
369→      } : undefined,
370→    };
371→  } catch (error) {
372→    if (error instanceof Error && error.name === 'AbortError') {
373→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
374→    }
375→    return {
376→      success: false,
377→      insights: [],
378→      error: error instanceof Error ? error.message : 'Prompt quality analysis failed',
379→      error_type: 'api_error',
380→    };
381→  }
382→}
