400→/**
401→ * Find recurring patterns across multiple insights and write bidirectional links to SQLite.
402→ */
403→export async function findRecurringInsights(
404→  insights: Array<{
405→    id: string;
406→    type: string;
407→    title: string;
408→    summary: string;
409→    project_name: string;
410→    session_id: string;
411→  }>
412→): Promise<RecurringInsightResult> {
413→  if (!isLLMConfigured()) {
414→    return { success: false, groups: [], updatedCount: 0, error: 'LLM not configured.' };
415→  }
416→
417→  const candidates = insights
418→    .filter(i => i.type !== 'summary' && i.type !== 'prompt_quality')
419→    .slice(0, 200);
420→
421→  if (candidates.length < 2) {
422→    return {
423→      success: false,
424→      groups: [],
425→      updatedCount: 0,
426→      error: 'Need at least 2 non-summary insights to find patterns.',
427→    };
428→  }
429→
430→  try {
431→    const client = createLLMClient();
432→
433→    const insightData = candidates.map(i => ({
434→      id: i.id,
435→      type: i.type === 'technique' ? 'learning' : i.type,
436→      title: i.title,
437→      summary: i.summary.slice(0, 150),
438→      projectName: i.project_name,
439→      sessionId: i.session_id,
440→    }));
441→
442→    const prompt = `Analyze these insights from coding sessions and find groups of semantically similar or duplicate insights — ones that express the same learning or decision even if worded differently.
443→
444→RULES:
445→- Only group insights that are genuinely about the same concept/topic
446→- Insights in a group should be from DIFFERENT sessions (same sessionId = not recurring)
447→- A group must have at least 2 insights
448→- An insight can only belong to one group
449→- Provide a brief "theme" describing what the group shares
450→- If no recurring patterns exist, return an empty groups array
451→
452→INSIGHTS:
453→${JSON.stringify(insightData, null, 2)}
454→
455→Respond with valid JSON only:
456→{
457→  "groups": [
458→    {
459→      "insightIds": ["insight_abc", "insight_def"],
460→      "theme": "Brief description of the shared concept"
461→    }
462→  ]
463→}`;
464→
465→    const response = await client.chat([
466→      {
467→        role: 'system',
468→        content: 'You are an expert at identifying recurring patterns and themes across software development insights. You find semantically similar insights even when they are worded differently. Respond with valid JSON only.',
469→      },
470→      { role: 'user', content: prompt },
471→    ]);
472→
473→    const jsonMatch = response.content.match(/\{[\s\S]*\}/);
474→    if (!jsonMatch) {
475→      return { success: false, groups: [], updatedCount: 0, error: 'Failed to parse recurring insights response.' };
476→    }
477→
478→    const parsed = JSON.parse(jsonMatch[0]) as { groups: RecurringInsightGroup[] };
479→    const groups = parsed.groups || [];
480→
481→    const validIds = new Set(candidates.map(i => i.id));
482→    const validGroups = groups
483→      .map(g => ({
484→        ...g,
485→        insightIds: g.insightIds.filter(id => validIds.has(id)),
486→      }))
487→      .filter(g => g.insightIds.length >= 2);
488→
489→    if (validGroups.length === 0) {
490→      return {
491→        success: true,
492→        groups: [],
493→        updatedCount: 0,
494→        usage: response.usage
495→          ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
496→          : undefined,
497→      };
498→    }
499→
500→    // Build bidirectional links
501→    const linkMap = new Map<string, string[]>();
502→    for (const group of validGroups) {
503→      for (const id of group.insightIds) {
504→        const others = group.insightIds.filter(otherId => otherId !== id);
505→        const existing = linkMap.get(id) || [];
506→        linkMap.set(id, [...new Set([...existing, ...others])]);
507→      }
508→    }
509→
510→    // Write links to SQLite
511→    const db = getDb();
512→    const updateLinks = db.prepare(
513→      `UPDATE insights SET linked_insight_ids = ? WHERE id = ?`
514→    );
515→
516→    for (const [insightId, linkedIds] of linkMap.entries()) {
517→      updateLinks.run(JSON.stringify(linkedIds), insightId);
518→    }
519→
520→    return {
521→      success: true,
522→      groups: validGroups,
523→      updatedCount: linkMap.size,
524→      usage: response.usage
525→        ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
526→        : undefined,
527→    };
528→  } catch (error) {
529→    return {
530→      success: false,
531→      groups: [],
532→      updatedCount: 0,
533→      error: error instanceof Error ? error.message : 'Failed to find recurring insights',
534→    };
535→  }
536→}
