538→// --- Internal helpers ---
539→
540→function chunkMessages(
541→  messages: SQLiteMessageRow[],
542→  estimateTokens: (text: string) => number
543→): SQLiteMessageRow[][] {
544→  const chunks: SQLiteMessageRow[][] = [];
545→  let currentChunk: SQLiteMessageRow[] = [];
546→  let currentTokens = 0;
547→  const chunkLimit = MAX_INPUT_TOKENS * 0.8;
548→
549→  for (const message of messages) {
550→    let toolResults: Array<{ output?: string }> = [];
551→    try {
552→      toolResults = message.tool_results ? JSON.parse(message.tool_results) as Array<{ output?: string }> : [];
553→    } catch {
554→      toolResults = [];
555→    }
556→
557→    const messageText = [
558→      message.content,
559→      message.thinking?.slice(0, 1000) ?? '',
560→      ...toolResults.map(r => (r.output || '').slice(0, 500)),
561→    ].join(' ');
562→    const messageTokens = estimateTokens(messageText);
563→
564→    if (currentTokens + messageTokens > chunkLimit && currentChunk.length > 0) {
565→      chunks.push(currentChunk);
566→      currentChunk = [];
567→      currentTokens = 0;
568→    }
569→
570→    currentChunk.push(message);
571→    currentTokens += messageTokens;
572→  }
573→
574→  if (currentChunk.length > 0) {
575→    chunks.push(currentChunk);
576→  }
577→
578→  return chunks;
579→}
