581→function mergeAnalysisResponses(responses: AnalysisResponse[]): AnalysisResponse {
582→  if (responses.length === 0) {
583→    return {
584→      summary: { title: 'Analysis failed', content: '', bullets: [] },
585→      decisions: [],
586→      learnings: [],
587→    };
588→  }
589→
590→  if (responses.length === 1) return responses[0];
591→
592→  const merged: AnalysisResponse = {
593→    session_character: responses.find(r => r.session_character)?.session_character,
594→    summary: responses[0].summary,
595→    decisions: [],
596→    learnings: [],
597→  };
598→
599→  for (const response of responses) {
600→    merged.decisions.push(...response.decisions);
601→    merged.learnings.push(...response.learnings);
602→  }
603→
604→  merged.decisions = deduplicateByTitle(merged.decisions).slice(0, 3);
605→  merged.learnings = deduplicateByTitle(merged.learnings).slice(0, 5);
606→
607→  return merged;
608→}
609→
610→function deduplicateByTitle<T extends { title: string }>(items: T[]): T[] {
611→  const seen = new Set<string>();
612→  return items.filter((item) => {
613→    const normalized = item.title.toLowerCase().trim();
614→    if (seen.has(normalized)) return false;
615→    seen.add(normalized);
616→    return true;
617→  });
618→}
