620→function convertToInsightRows(response: AnalysisResponse, session: SessionData): InsightRow[] {
621→  const insights: InsightRow[] = [];
622→  const now = new Date().toISOString();
623→
624→  insights.push({
625→    id: randomUUID(),
626→    session_id: session.id,
627→    project_id: session.project_id,
628→    project_name: session.project_name,
629→    type: 'summary',
630→    title: response.summary.title,
631→    content: response.summary.content,
632→    summary: response.summary.content,
633→    bullets: JSON.stringify(response.summary.bullets),
634→    confidence: 0.9,
635→    source: 'llm',
636→    metadata: response.summary.outcome
637→      ? JSON.stringify({ outcome: response.summary.outcome })
638→      : null,
639→    timestamp: session.ended_at,
640→    created_at: now,
641→    scope: 'session',
642→    analysis_version: ANALYSIS_VERSION,
643→  });
644→
645→  for (const decision of response.decisions) {
646→    const confidence = decision.confidence ?? 85;
647→    if (confidence < 70) continue;
648→
649→    const content = decision.situation && decision.choice
650→      ? `${decision.situation} → ${decision.choice}`
651→      : decision.choice || decision.situation || decision.title;
652→
653→    const altBullets = (decision.alternatives || [])
654→      .filter(a => a && typeof a === 'object' && a.option)
655→      .map(a => `${a.option}: ${a.rejected_because || 'no reason given'}`);
656→
657→    insights.push({
658→      id: randomUUID(),
659→      session_id: session.id,
660→      project_id: session.project_id,
661→      project_name: session.project_name,
662→      type: 'decision',
663→      title: decision.title,
664→      content,
665→      summary: (decision.choice || content).slice(0, 200),
666→      bullets: JSON.stringify(altBullets),
667→      confidence: confidence / 100,
668→      source: 'llm',
669→      metadata: JSON.stringify({
670→        situation: decision.situation,
671→        choice: decision.choice,
672→        reasoning: decision.reasoning,
673→        alternatives: decision.alternatives,
674→        trade_offs: decision.trade_offs,
675→        revisit_when: decision.revisit_when,
676→        evidence: decision.evidence,
677→      }),
678→      timestamp: session.ended_at,
679→      created_at: now,
680→      scope: 'session',
681→      analysis_version: ANALYSIS_VERSION,
682→    });
683→  }
684→
685→  for (const learning of response.learnings) {
686→    const confidence = learning.confidence ?? 80;
687→    if (confidence < 70) continue;
688→
689→    const content = learning.takeaway || learning.title;
690→
691→    insights.push({
692→      id: randomUUID(),
693→      session_id: session.id,
694→      project_id: session.project_id,
695→      project_name: session.project_name,
696→      type: 'learning',
697→      title: learning.title,
698→      content,
699→      summary: content.slice(0, 200),
700→      bullets: JSON.stringify([]),
701→      confidence: confidence / 100,
702→      source: 'llm',
703→      metadata: JSON.stringify({
704→        symptom: learning.symptom,
705→        root_cause: learning.root_cause,
706→        takeaway: learning.takeaway,
707→        applies_when: learning.applies_when,
708→        evidence: learning.evidence,
709→      }),
710→      timestamp: session.ended_at,
711→      created_at: now,
712→      scope: 'session',
713→      analysis_version: ANALYSIS_VERSION,
714→    });
715→  }
716→
717→  return insights;
718→}
