749→/**
750→ * Write insight rows to SQLite using prepared statements.
751→ */
752→function saveInsightsToDb(insights: InsightRow[]): void {
753→  const db = getDb();
754→  const insert = db.prepare(`
755→    INSERT OR REPLACE INTO insights (
756→      id, session_id, project_id, project_name, type, title, content,
757→      summary, bullets, confidence, source, metadata, timestamp,
758→      created_at, scope, analysis_version
759→    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
760→  `);
761→
762→  const insertMany = db.transaction((rows: InsightRow[]) => {
763→    for (const row of rows) {
764→      insert.run(
765→        row.id,
766→        row.session_id,
767→        row.project_id,
768→        row.project_name,
769→        row.type,
770→        row.title,
771→        row.content,
772→        row.summary,
773→        row.bullets,
774→        row.confidence,
775→        row.source,
776→        row.metadata,
777→        row.timestamp,
778→        row.created_at,
779→        row.scope,
780→        row.analysis_version,
781→      );
782→    }
783→  });
784→
785→  insertMany(insights);
786→}
