788→interface DeleteOptions {
789→  excludeTypes?: string[];
790→  includeOnlyTypes?: string[];
791→  excludeIds?: string[];
792→}
793→
794→/**
795→ * Delete insights for a session, with optional type and ID exclusions.
796→ */
797→function deleteSessionInsights(sessionId: string, opts: DeleteOptions): void {
798→  const db = getDb();
799→  const conditions: string[] = ['session_id = ?'];
800→  const params: (string | number)[] = [sessionId];
801→
802→  if (opts.excludeTypes && opts.excludeTypes.length > 0) {
803→    conditions.push(`type NOT IN (${opts.excludeTypes.map(() => '?').join(', ')})`);
804→    params.push(...opts.excludeTypes);
805→  }
806→
807→  if (opts.includeOnlyTypes && opts.includeOnlyTypes.length > 0) {
808→    conditions.push(`type IN (${opts.includeOnlyTypes.map(() => '?').join(', ')})`);
809→    params.push(...opts.includeOnlyTypes);
810→  }
811→
812→  if (opts.excludeIds && opts.excludeIds.length > 0) {
813→    conditions.push(`id NOT IN (${opts.excludeIds.map(() => '?').join(', ')})`);
814→    params.push(...opts.excludeIds);
815→  }
816→
817→  db.prepare(`DELETE FROM insights WHERE ${conditions.join(' AND ')}`).run(...params);
818→}
