820→/**
821→ * Save extracted facets to the session_facets table.
822→ */
823→function saveFacetsToDb(
824→  sessionId: string,
825→  facets: NonNullable<AnalysisResponse['facets']>,
826→  analysisVersion: string
827→): void {
828→  const db = getDb();
829→
830→  // Normalize pattern categories at write time so stored data is always clean.
831→  // This handles LLM variants (e.g., "task-decomposition" → "structured-planning")
832→  // before they hit the database, keeping aggregation queries simple.
833→  const normalizedPatterns = Array.isArray(facets.effective_patterns)
834→    ? facets.effective_patterns.map(ep => {
835→        if (!ep.category) {
836→          // Should not happen with updated prompts — indicates model ignored category instruction.
837→          // Fall back to 'uncategorized' so these sessions don't trigger the outdated banner.
838→          console.warn('[pattern-monitor] saveFacetsToDb: effective_pattern missing category field, defaulting to uncategorized');
839→        }
840→        return {
841→          ...ep,
842→          category: ep.category ? normalizePatternCategory(ep.category) : 'uncategorized',
843→        };
844→      })
845→    : [];
846→
847→  db.prepare(`
848→    INSERT OR REPLACE INTO session_facets
849→    (session_id, outcome_satisfaction, workflow_pattern, had_course_correction,
850→     course_correction_reason, iteration_count, friction_points, effective_patterns,
851→     analysis_version)
852→    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
853→  `).run(
854→    sessionId,
855→    facets.outcome_satisfaction,
856→    facets.workflow_pattern,
857→    facets.had_course_correction ? 1 : 0,
858→    facets.course_correction_reason,
859→    facets.iteration_count,
860→    JSON.stringify(Array.isArray(facets.friction_points) ? facets.friction_points : []),
861→    JSON.stringify(normalizedPatterns),
862→    analysisVersion
863→  );
864→}
