866→/**
867→ * Extract facets only for a session that already has insights (backfill).
868→ * Uses lightweight prompt with summary + first/last 20 messages.
869→ */
870→export async function extractFacetsOnly(
871→  session: SessionData,
872→  messages: SQLiteMessageRow[],
873→  options?: { signal?: AbortSignal }
874→): Promise<{ success: boolean; error?: string }> {
875→  if (!isLLMConfigured()) {
876→    return { success: false, error: 'LLM not configured.' };
877→  }
878→
879→  if (messages.length === 0) {
880→    return { success: false, error: 'No messages found.' };
881→  }
882→
883→  try {
884→    const client = createLLMClient();
885→    const firstMsgs = formatMessagesForAnalysis(messages.slice(0, 20));
886→    const lastMsgs = formatMessagesForAnalysis(messages.slice(-20));
887→    const prompt = generateFacetOnlyPrompt(
888→      session.project_name,
889→      session.summary,
890→      firstMsgs,
891→      lastMsgs
892→    );
893→
894→    const response = await client.chat([
